import React, { useState, useEffect, useMemo } from "react";
import { Home, Users, CalendarDays, Wallet, Settings, Plus, Trash2, CheckCircle2, Circle, ExternalLink, PawPrint, X, PackageOpen, Camera, Car } from "lucide-react";
import { supabase } from "./supabaseClient";

const LOGO_ICON = "data:image/png;base64,";

const uid = () => Date.now().toString(36) + Math.random().toString(36).slice(2, 7);
const todayISO = () => new Date().toISOString().slice(0, 10);
const brl = (n) => (Number(n) || 0).toLocaleString("pt-BR", { style: "currency", currency: "BRL" });

function comprimirFoto(file, maxLado = 360, qualidade = 0.7) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onerror = reject;
    reader.onload = () => {
      const img = new Image();
      img.onerror = reject;
      img.onload = () => {
        const escala = Math.min(1, maxLado / Math.max(img.width, img.height));
        const w = Math.round(img.width * escala);
        const h = Math.round(img.height * escala);
        const canvas = document.createElement("canvas");
        canvas.width = w;
        canvas.height = h;
        canvas.getContext("2d").drawImage(img, 0, 0, w, h);
        resolve(canvas.toDataURL("image/jpeg", qualidade));
      };
      img.src = reader.result;
    };
    reader.readAsDataURL(file);
  });
}

const DEFAULT_DB = {
  clientes: [],
  pets: [],
  servicos: [
    { id: uid(), nome: "Banho", preco: 60 },
    { id: uid(), nome: "Tosa higiênica", preco: 40 },
    { id: uid(), nome: "Banho + Tosa", preco: 90 },
    { id: uid(), nome: "Hidratação", preco: 50 },
  ],
  pacotes: [],
  agendamentos: [],
  financeiro: [],
};

function gcalLink({ titulo, dataISO, hora, duracaoMin = 60, detalhes = "" }) {
  const [h, m] = (hora || "09:00").split(":").map(Number);
  const start = new Date(dataISO + "T00:00:00");
  start.setHours(h, m, 0, 0);
  const end = new Date(start.getTime() + duracaoMin * 60000);
  const fmt = (d) => d.toISOString().replace(/[-:]/g, "").split(".")[0] + "Z";
  const params = new URLSearchParams({
    action: "TEMPLATE",
    text: titulo,
    dates: `${fmt(start)}/${fmt(end)}`,
    details: detalhes,
  });
  return `https://www.google.com/calendar/render?${params.toString()}`;
}

export default function App() {
  const [db, setDb] = useState(null);
  const [tab, setTab] = useState("dashboard");
  const [loaded, setLoaded] = useState(false);

  useEffect(() => {
    (async () => {
      try {
        const { data, error } = await supabase
          .from("app_storage")
          .select("value")
          .eq("key", "refugio-db")
          .maybeSingle();
        if (error) throw error;
        setDb(data && data.value ? data.value : DEFAULT_DB);
      } catch (e) {
        console.error("Erro ao carregar dados:", e);
        setDb(DEFAULT_DB);
      }
      setLoaded(true);
    })();

    // Atualiza em tempo real quando outro funcionário altera os dados
    const channel = supabase
      .channel("refugio-db-changes")
      .on(
        "postgres_changes",
        { event: "*", schema: "public", table: "app_storage", filter: "key=eq.refugio-db" },
        (payload) => {
          if (payload.new && payload.new.value) setDb(payload.new.value);
        }
      )
      .subscribe();

    return () => supabase.removeChannel(channel);
  }, []);

  const persist = async (next) => {
    setDb(next);
    try {
      await supabase.from("app_storage").upsert({ key: "refugio-db", value: next, updated_at: new Date().toISOString() });
    } catch (e) {
      console.error("Erro ao salvar dados:", e);
    }
  };

  if (!loaded || !db) {
    return (
      <div style={{ padding: 40, textAlign: "center", color: "#8C7A67", fontFamily: "'DM Sans', sans-serif" }}>
        Carregando o refúgio…
      </div>
    );
  }

  const tabs = [
    { id: "dashboard", label: "Painel", icon: Home },
    { id: "clientes", label: "Clientes e pets", icon: Users },
    { id: "agenda", label: "Agenda", icon: CalendarDays },
    { id: "financeiro", label: "Financeiro", icon: Wallet },
    { id: "config", label: "Serviços", icon: Settings },
  ];

  return (
    <div style={{ fontFamily: "'DM Sans', sans-serif", background: "#F8F1E0", minHeight: "100vh", color: "#3A2E24" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Fraunces:wght@500;600&family=DM+Sans:wght@400;500;600&display=swap');
        .rp-card{background:#fff;border:1px solid #E6D9BE;border-radius:14px;padding:20px}
        .rp-btn{background:#624739;color:#F8F1E0;border:none;border-radius:8px;padding:9px 16px;font-size:14px;font-weight:500;cursor:pointer;font-family:inherit}
        .rp-btn:hover{background:#4E362B}
        .rp-btn-ghost{background:transparent;color:#624739;border:1px solid #CBB98F;border-radius:8px;padding:8px 14px;font-size:13px;cursor:pointer;font-family:inherit}
        .rp-btn-danger{background:transparent;color:#A5493A;border:1px solid #E3C9C1;border-radius:8px;padding:6px 10px;font-size:13px;cursor:pointer}
        .rp-input, .rp-select{border:1px solid #DDD0AE;border-radius:8px;padding:8px 10px;font-size:14px;font-family:inherit;background:#FCF8EE;width:100%;box-sizing:border-box}
        .rp-label{font-size:12px;color:#8C7A67;margin-bottom:4px;display:block;font-weight:500}
        .rp-title{font-family:'Fraunces',serif;font-weight:600}
        .rp-tag{display:inline-block;padding:3px 9px;border-radius:20px;font-size:12px;font-weight:500}
      `}</style>

      <div style={{ display: "flex", maxWidth: 1100, margin: "0 auto" }}>
        <nav style={{ width: 210, padding: "28px 12px", flexShrink: 0 }}>
          <div style={{ padding: "0 12px 24px", display: "flex", alignItems: "center", gap: 10 }}>
            <img src={LOGO_ICON} alt="Refúgio do Pet" style={{ width: 34, height: "auto", flexShrink: 0 }} />
            <div>
              <div className="rp-title" style={{ fontSize: 17, color: "#624739", lineHeight: 1.15 }}>Refúgio<br />do Pet</div>
              <div style={{ fontSize: 11, color: "#96876F" }}>painel interno</div>
            </div>
          </div>
          {tabs.map((t) => {
            const Icon = t.icon;
            const active = tab === t.id;
            return (
              <button
                key={t.id}
                onClick={() => setTab(t.id)}
                style={{
                  display: "flex", alignItems: "center", gap: 10, width: "100%",
                  padding: "10px 12px", marginBottom: 4, borderRadius: 8, border: "none",
                  background: active ? "#624739" : "transparent",
                  color: active ? "#F8F1E0" : "#5B4A3B",
                  fontSize: 14, fontWeight: 500, cursor: "pointer", textAlign: "left", fontFamily: "inherit",
                }}
              >
                <Icon size={17} />
                {t.label}
              </button>
            );
          })}
        </nav>

        <main style={{ flex: 1, padding: "28px 24px 60px", minWidth: 0 }}>
          {tab === "dashboard" && <Dashboard db={db} />}
          {tab === "clientes" && <ClientesPets db={db} persist={persist} />}
          {tab === "agenda" && <Agenda db={db} persist={persist} />}
          {tab === "financeiro" && <Financeiro db={db} persist={persist} />}
          {tab === "config" && <Servicos db={db} persist={persist} />}
        </main>
      </div>
    </div>
  );
}

function Dashboard({ db }) {
  const mesAtual = todayISO().slice(0, 7);
  const entradasMes = db.financeiro.filter((f) => f.tipo === "entrada" && f.data.startsWith(mesAtual)).reduce((s, f) => s + Number(f.valor), 0);
  const saidasMes = db.financeiro.filter((f) => f.tipo === "saida" && f.data.startsWith(mesAtual)).reduce((s, f) => s + Number(f.valor), 0);
  const saldo = entradasMes - saidasMes;

  const proximos = db.agendamentos
    .filter((a) => a.status === "agendado" && a.data >= todayISO())
    .sort((a, b) => (a.data + a.hora).localeCompare(b.data + b.hora))
    .slice(0, 5);

  const creditosAtivos = db.pacotes.filter((p) => p.creditosUsados < p.creditosTotal);

  let clima = { label: "Tranquilo", cor: "#065748", bg: "#E1EBE0" };
  if (saldo < 0) clima = { label: "Tenso", cor: "#A5493A", bg: "#F5E4DF" };
  else if (saldo < 300) clima = { label: "Atenção", cor: "#9A7A2E", bg: "#F3ECD9" };

  const nome = (id, arr, key = "nome") => arr.find((x) => x.id === id)?.[key] || "—";

  return (
    <div>
      <h2 className="rp-title" style={{ fontSize: 21, margin: "0 0 4px" }}>Painel</h2>
      <p style={{ color: "#96876F", fontSize: 13, margin: "0 0 20px" }}>Como está o mês, sem pressa e sem improviso.</p>

      <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 12, marginBottom: 20 }}>
        <div className="rp-card">
          <div style={{ fontSize: 12, color: "#96876F" }}>Entradas do mês</div>
          <div style={{ fontSize: 22, fontWeight: 600, marginTop: 4 }}>{brl(entradasMes)}</div>
        </div>
        <div className="rp-card">
          <div style={{ fontSize: 12, color: "#96876F" }}>Saídas do mês</div>
          <div style={{ fontSize: 22, fontWeight: 600, marginTop: 4 }}>{brl(saidasMes)}</div>
        </div>
        <div className="rp-card">
          <div style={{ fontSize: 12, color: "#96876F" }}>Saldo do mês</div>
          <div style={{ fontSize: 22, fontWeight: 600, marginTop: 4, color: saldo < 0 ? "#A5493A" : "#3A2E24" }}>{brl(saldo)}</div>
        </div>
        <div className="rp-card" style={{ background: clima.bg, border: "none" }}>
          <div style={{ fontSize: 12, color: clima.cor }}>Termômetro de calma</div>
          <div style={{ fontSize: 22, fontWeight: 600, marginTop: 4, color: clima.cor }}>{clima.label}</div>
        </div>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "1.3fr 1fr", gap: 16 }}>
        <div className="rp-card">
          <div style={{ fontWeight: 600, marginBottom: 12, fontSize: 14 }}>Próximos agendamentos</div>
          {proximos.length === 0 && <div style={{ fontSize: 13, color: "#96876F" }}>Nada agendado ainda. Combine um horário na aba Agenda.</div>}
          {proximos.map((a) => (
            <div key={a.id} style={{ display: "flex", justifyContent: "space-between", padding: "8px 0", borderBottom: "1px solid #F8F1E0", fontSize: 13 }}>
              <span>{nome(a.petId, db.pets)} · {(a.servicoIds || []).map((id) => nome(id, db.servicos)).join(" + ") || (a.pacoteId ? "crédito de pacote" : "—")}</span>
              <span style={{ color: "#96876F" }}>{a.data.split("-").reverse().join("/")} às {a.hora}</span>
            </div>
          ))}
        </div>
        <div className="rp-card">
          <div style={{ fontWeight: 600, marginBottom: 12, fontSize: 14 }}>Créditos de pacote ativos</div>
          {creditosAtivos.length === 0 && <div style={{ fontSize: 13, color: "#96876F" }}>Nenhum pacote com créditos em aberto.</div>}
          {creditosAtivos.map((p) => (
            <div key={p.id} style={{ display: "flex", justifyContent: "space-between", padding: "8px 0", borderBottom: "1px solid #F8F1E0", fontSize: 13 }}>
              <span>{nome(p.petId, db.pets)}</span>
              <span style={{ color: "#96876F" }}>{p.creditosTotal - p.creditosUsados} de {p.creditosTotal} restantes</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

const PET_VAZIO = { nome: "", especie: "Cão", raca: "", porte: "Médio", idade: "", obs: "", usaPetMovel: false, foto: "" };

const PLANOS_PADRAO = [
  { nome: "Plano Essencial", creditosTotal: 2, valorPago: 135, descricao: "2 banhos completos com hidratação, corte das unhas, limpeza dos ouvidos e tosa higiênica" },
  { nome: "Plano Cuidado", creditosTotal: 3, valorPago: 195, descricao: "3 banhos completos com hidratação, corte das unhas, limpeza dos ouvidos e tosa higiênica" },
  { nome: "Plano Completo", creditosTotal: 4, valorPago: 260, descricao: "4 banhos completos para o pet passar o mês todo limpinho, cheiroso e bem cuidado" },
];

function ClientesPets({ db, persist }) {
  const [novoCliente, setNovoCliente] = useState({ nome: "", telefone: "", endereco: "" });
  const [primeiroPet, setPrimeiroPet] = useState({ ...PET_VAZIO });
  const [novoPet, setNovoPet] = useState({});
  const [aberto, setAberto] = useState(null);
  const [petAberto, setPetAberto] = useState(null);
  const [pacoteAberto, setPacoteAberto] = useState(null);
  const [novoPacotePet, setNovoPacotePet] = useState({});
  const [busca, setBusca] = useState("");

  const onFotoPrimeiroPet = async (file) => {
    if (!file) return;
    const dataUrl = await comprimirFoto(file);
    setPrimeiroPet({ ...primeiroPet, foto: dataUrl });
  };

  const addClienteComPet = () => {
    if (!novoCliente.nome.trim()) return;
    const clienteId = uid();
    const next = { ...db, clientes: [...db.clientes, { id: clienteId, ...novoCliente }] };
    if (primeiroPet.nome.trim()) {
      next.pets = [...db.pets, { id: uid(), clienteId, ...primeiroPet }];
    }
    persist(next);
    setNovoCliente({ nome: "", telefone: "", endereco: "" });
    setPrimeiroPet({ ...PET_VAZIO });
  };

  const addPet = (clienteId) => {
    const p = novoPet[clienteId];
    if (!p || !p.nome?.trim()) return;
    persist({ ...db, pets: [...db.pets, { id: uid(), clienteId, ...PET_VAZIO, ...p }] });
    setNovoPet({ ...novoPet, [clienteId]: { ...PET_VAZIO } });
  };

  const salvarPetExistente = (petId, campo, valor) => {
    persist({ ...db, pets: db.pets.map((p) => (p.id === petId ? { ...p, [campo]: valor } : p)) });
  };

  const onFoto = async (clienteId, file, petIdExistente) => {
    if (!file) return;
    const dataUrl = await comprimirFoto(file);
    if (petIdExistente) salvarPetExistente(petIdExistente, "foto", dataUrl);
    else setNovoPet({ ...novoPet, [clienteId]: { ...(novoPet[clienteId] || PET_VAZIO), foto: dataUrl } });
  };

  const removerCliente = (id) => {
    persist({ ...db, clientes: db.clientes.filter((c) => c.id !== id), pets: db.pets.filter((p) => p.clienteId !== id) });
  };

  const removerPet = (id) => persist({ ...db, pets: db.pets.filter((p) => p.id !== id) });

  const criarPacote = (petId) => {
    const np = novoPacotePet[petId] || { nome: "", creditosTotal: "", valorPago: "" };
    if (!np.nome?.trim() || !Number(np.creditosTotal)) return;
    const pet = db.pets.find((x) => x.id === petId);
    const descricao = PLANOS_PADRAO.find((pl) => pl.nome === np.planoBase)?.descricao || "";
    const pac = { id: uid(), petId, nome: np.nome, descricao, creditosTotal: Number(np.creditosTotal), valorPago: Number(np.valorPago) || 0, creditosUsados: 0, dataCompra: todayISO() };
    persist({
      ...db,
      pacotes: [...db.pacotes, pac],
      financeiro: [...db.financeiro, { id: uid(), tipo: "entrada", categoria: "Pacote", valor: Number(np.valorPago) || 0, data: todayISO(), descricao: `${np.nome} — ${pet?.nome || ""}` }],
    });
    setNovoPacotePet({ ...novoPacotePet, [petId]: { nome: "", creditosTotal: "", valorPago: "", planoBase: "" } });
  };

  const removerPacote = (id) => persist({ ...db, pacotes: db.pacotes.filter((p) => p.id !== id) });

  const clientesFiltrados = db.clientes.filter((c) => {
    if (!busca.trim()) return true;
    const q = busca.trim().toLowerCase();
    if (c.nome.toLowerCase().includes(q)) return true;
    return db.pets.some((p) => p.clienteId === c.id && p.nome.toLowerCase().includes(q));
  });

  return (
    <div>
      <h2 className="rp-title" style={{ fontSize: 21, margin: "0 0 4px" }}>Clientes e pets</h2>
      <p style={{ color: "#96876F", fontSize: 13, margin: "0 0 20px" }}>Cada tutor, com os pets que confiam a você.</p>

      <div className="rp-card" style={{ marginBottom: 20 }}>
        <div style={{ fontSize: 13, fontWeight: 600, marginBottom: 10, color: "#8C7A67" }}>Dados do tutor</div>
        <div style={{ display: "flex", gap: 10, flexWrap: "wrap", alignItems: "flex-end", marginBottom: 16 }}>
          <div style={{ flex: 1, minWidth: 160 }}>
            <label className="rp-label">Nome do tutor</label>
            <input className="rp-input" value={novoCliente.nome} onChange={(e) => setNovoCliente({ ...novoCliente, nome: e.target.value })} placeholder="Nome completo" />
          </div>
          <div style={{ flex: 1, minWidth: 130 }}>
            <label className="rp-label">Telefone</label>
            <input className="rp-input" value={novoCliente.telefone} onChange={(e) => setNovoCliente({ ...novoCliente, telefone: e.target.value })} placeholder="(00) 00000-0000" />
          </div>
          <div style={{ flex: 2, minWidth: 200 }}>
            <label className="rp-label">Endereço</label>
            <input className="rp-input" value={novoCliente.endereco} onChange={(e) => setNovoCliente({ ...novoCliente, endereco: e.target.value })} placeholder="Rua, número, bairro" />
          </div>
        </div>

        <div style={{ fontSize: 13, fontWeight: 600, marginBottom: 10, color: "#8C7A67", borderTop: "1px solid #F8F1E0", paddingTop: 14 }}>Dados do pet</div>
        <div style={{ display: "flex", gap: 10, flexWrap: "wrap", alignItems: "flex-end" }}>
          <div style={{ flex: 1, minWidth: 130 }}>
            <label className="rp-label">Nome do pet</label>
            <input className="rp-input" value={primeiroPet.nome} onChange={(e) => setPrimeiroPet({ ...primeiroPet, nome: e.target.value })} placeholder="Nome" />
          </div>
          <div style={{ minWidth: 100 }}>
            <label className="rp-label">Espécie</label>
            <select className="rp-select" value={primeiroPet.especie} onChange={(e) => setPrimeiroPet({ ...primeiroPet, especie: e.target.value })}>
              <option>Cão</option><option>Gato</option><option>Outro</option>
            </select>
          </div>
          <div style={{ flex: 1, minWidth: 110 }}>
            <label className="rp-label">Raça</label>
            <input className="rp-input" value={primeiroPet.raca} onChange={(e) => setPrimeiroPet({ ...primeiroPet, raca: e.target.value })} placeholder="Raça" />
          </div>
          <div style={{ minWidth: 100 }}>
            <label className="rp-label">Porte</label>
            <select className="rp-select" value={primeiroPet.porte} onChange={(e) => setPrimeiroPet({ ...primeiroPet, porte: e.target.value })}>
              <option>Pequeno</option><option>Médio</option><option>Grande</option>
            </select>
          </div>
          <div style={{ minWidth: 80 }}>
            <label className="rp-label">Idade</label>
            <input className="rp-input" value={primeiroPet.idade} onChange={(e) => setPrimeiroPet({ ...primeiroPet, idade: e.target.value })} placeholder="anos" />
          </div>
          <div style={{ flex: 2, minWidth: 180 }}>
            <label className="rp-label">Características de comportamento</label>
            <input className="rp-input" value={primeiroPet.obs} onChange={(e) => setPrimeiroPet({ ...primeiroPet, obs: e.target.value })} placeholder="Ex: dócil, medo de barulho" />
          </div>
          <div>
            <label className="rp-label">Pet móvel</label>
            <label style={{ fontSize: 13, display: "flex", alignItems: "center", gap: 6, height: 36 }}>
              <input type="checkbox" checked={primeiroPet.usaPetMovel} onChange={(e) => setPrimeiroPet({ ...primeiroPet, usaPetMovel: e.target.checked })} /> Usa
            </label>
          </div>
          <div>
            <label className="rp-label">Foto</label>
            <label className="rp-btn-ghost" style={{ display: "inline-flex", alignItems: "center", gap: 6, cursor: "pointer" }}>
              <Camera size={14} /> {primeiroPet.foto ? "Trocada" : "Subir"}
              <input type="file" accept="image/*" style={{ display: "none" }} onChange={(e) => onFotoPrimeiroPet(e.target.files[0])} />
            </label>
          </div>
          <button className="rp-btn" onClick={addClienteComPet}><Plus size={14} style={{ verticalAlign: -2 }} /> Cadastrar tutor e pet</button>
        </div>
      </div>

      <div style={{ marginBottom: 16, position: "relative", maxWidth: 340 }}>
        <input
          className="rp-input"
          value={busca}
          onChange={(e) => setBusca(e.target.value)}
          placeholder="Buscar por tutor ou pet..."
        />
      </div>

      {db.clientes.length === 0 && <div style={{ color: "#96876F", fontSize: 13 }}>Nenhum cliente cadastrado ainda.</div>}
      {db.clientes.length > 0 && clientesFiltrados.length === 0 && (
        <div style={{ color: "#96876F", fontSize: 13 }}>Nenhum tutor ou pet encontrado para "{busca}".</div>
      )}

      {clientesFiltrados.map((c) => {
        const petsDoCliente = db.pets.filter((p) => p.clienteId === c.id);
        const editando = aberto === c.id;
        const formPet = novoPet[c.id] || { ...PET_VAZIO };
        return (
          <div key={c.id} className="rp-card" style={{ marginBottom: 12 }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
              <div>
                <div style={{ fontWeight: 600, fontSize: 15 }}>{c.nome}</div>
                <div style={{ fontSize: 12, color: "#96876F" }}>
                  {c.telefone}{c.endereco ? ` · ${c.endereco}` : ""}
                  {petsDoCliente.length > 0 && ` · ${petsDoCliente.length} pet${petsDoCliente.length > 1 ? "s" : ""}`}
                </div>
              </div>
              <div style={{ display: "flex", gap: 8 }}>
                <button className="rp-btn-ghost" onClick={() => setAberto(editando ? null : c.id)}>
                  {editando ? "Fechar" : petsDoCliente.length > 0 ? "Adicionar outro pet" : "Adicionar pet"}
                </button>
                <button className="rp-btn-danger" onClick={() => removerCliente(c.id)}><Trash2 size={13} /></button>
              </div>
            </div>

            {petsDoCliente.length > 0 && (
              <div style={{ marginTop: 12, display: "flex", flexWrap: "wrap", gap: 10 }}>
                {petsDoCliente.map((p) => {
                  const petEditando = petAberto === p.id;
                  return (
                    <div key={p.id} style={{ border: "1px solid #E6D9BE", borderRadius: 10, padding: 8, width: 150 }}>
                      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
                        <div style={{
                          width: 44, height: 44, borderRadius: 8, background: "#F8F1E0", flexShrink: 0,
                          backgroundImage: p.foto ? `url(${p.foto})` : "none", backgroundSize: "cover", backgroundPosition: "center",
                          display: "flex", alignItems: "center", justifyContent: "center", color: "#96876F",
                        }}>
                          {!p.foto && <PawPrint size={18} />}
                        </div>
                        <X size={13} style={{ cursor: "pointer", color: "#A5493A" }} onClick={() => removerPet(p.id)} />
                      </div>
                      <div style={{ fontSize: 13, fontWeight: 600, marginTop: 6 }}>{p.nome}</div>
                      <div style={{ fontSize: 11, color: "#96876F" }}>{p.especie} · {p.raca || "s/ raça"}</div>
                      <div style={{ fontSize: 11, color: "#96876F" }}>Porte {p.porte} · {p.idade ? `${p.idade} anos` : "idade ?"}</div>
                      {p.usaPetMovel && <span className="rp-tag" style={{ background: "#E4EFF6", color: "#2C5875", fontSize: 10, marginTop: 4, display: "inline-flex", alignItems: "center", gap: 3 }}><Car size={10} /> pet móvel</span>}
                      {(() => {
                        const creditos = db.pacotes.filter((pac) => pac.petId === p.id && pac.creditosUsados < pac.creditosTotal)
                          .reduce((s, pac) => s + (pac.creditosTotal - pac.creditosUsados), 0);
                        return creditos > 0 ? (
                          <span className="rp-tag" style={{ background: "#F3ECD9", color: "#9A7A2E", fontSize: 10, marginTop: 4, marginLeft: p.usaPetMovel ? 4 : 0, display: "inline-flex", alignItems: "center", gap: 3 }}>
                            <PackageOpen size={10} /> {creditos} créditos
                          </span>
                        ) : null;
                      })()}
                      <button className="rp-btn-ghost" style={{ width: "100%", marginTop: 4, padding: "4px 0", fontSize: 11 }} onClick={() => setPacoteAberto(pacoteAberto === p.id ? null : p.id)}>
                        <PackageOpen size={11} style={{ verticalAlign: -1 }} /> Pacotes
                      </button>
                      <button className="rp-btn-ghost" style={{ width: "100%", marginTop: 6, padding: "4px 0", fontSize: 11 }} onClick={() => setPetAberto(petEditando ? null : p.id)}>
                        {petEditando ? "Fechar" : "Editar"}
                      </button>
                      {petEditando && (
                        <div style={{ marginTop: 6, display: "flex", flexDirection: "column", gap: 6 }}>
                          <label className="rp-label" style={{ marginBottom: 0 }}>Raça</label>
                          <input className="rp-input" value={p.raca} onChange={(e) => salvarPetExistente(p.id, "raca", e.target.value)} />
                          <label className="rp-label" style={{ marginBottom: 0 }}>Porte</label>
                          <select className="rp-select" value={p.porte} onChange={(e) => salvarPetExistente(p.id, "porte", e.target.value)}>
                            <option>Pequeno</option><option>Médio</option><option>Grande</option>
                          </select>
                          <label className="rp-label" style={{ marginBottom: 0 }}>Idade</label>
                          <input className="rp-input" value={p.idade} onChange={(e) => salvarPetExistente(p.id, "idade", e.target.value)} placeholder="anos" />
                          <label className="rp-label" style={{ marginBottom: 0 }}>Comportamento</label>
                          <input className="rp-input" value={p.obs} onChange={(e) => salvarPetExistente(p.id, "obs", e.target.value)} placeholder="Ex: assustado com secador" />
                          <label style={{ fontSize: 11, display: "flex", alignItems: "center", gap: 6 }}>
                            <input type="checkbox" checked={p.usaPetMovel} onChange={(e) => salvarPetExistente(p.id, "usaPetMovel", e.target.checked)} /> Usa pet móvel
                          </label>
                          <label className="rp-btn-ghost" style={{ textAlign: "center", fontSize: 11, cursor: "pointer" }}>
                            <Camera size={12} style={{ verticalAlign: -2 }} /> Trocar foto
                            <input type="file" accept="image/*" style={{ display: "none" }} onChange={(e) => onFoto(c.id, e.target.files[0], p.id)} />
                          </label>
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}

            {editando && (
              <div style={{ marginTop: 14, paddingTop: 14, borderTop: "1px solid #F8F1E0" }}>
                <div style={{ fontSize: 13, fontWeight: 600, marginBottom: 8 }}>Novo pet</div>
                <div style={{ display: "flex", gap: 10, flexWrap: "wrap", alignItems: "flex-end" }}>
                  <div style={{ flex: 1, minWidth: 120 }}>
                    <label className="rp-label">Nome do pet</label>
                    <input className="rp-input" value={formPet.nome} onChange={(e) => setNovoPet({ ...novoPet, [c.id]: { ...formPet, nome: e.target.value } })} />
                  </div>
                  <div style={{ minWidth: 100 }}>
                    <label className="rp-label">Espécie</label>
                    <select className="rp-select" value={formPet.especie} onChange={(e) => setNovoPet({ ...novoPet, [c.id]: { ...formPet, especie: e.target.value } })}>
                      <option>Cão</option><option>Gato</option><option>Outro</option>
                    </select>
                  </div>
                  <div style={{ flex: 1, minWidth: 110 }}>
                    <label className="rp-label">Raça</label>
                    <input className="rp-input" value={formPet.raca} onChange={(e) => setNovoPet({ ...novoPet, [c.id]: { ...formPet, raca: e.target.value } })} />
                  </div>
                  <div style={{ minWidth: 100 }}>
                    <label className="rp-label">Porte</label>
                    <select className="rp-select" value={formPet.porte} onChange={(e) => setNovoPet({ ...novoPet, [c.id]: { ...formPet, porte: e.target.value } })}>
                      <option>Pequeno</option><option>Médio</option><option>Grande</option>
                    </select>
                  </div>
                  <div style={{ minWidth: 80 }}>
                    <label className="rp-label">Idade</label>
                    <input className="rp-input" value={formPet.idade} onChange={(e) => setNovoPet({ ...novoPet, [c.id]: { ...formPet, idade: e.target.value } })} placeholder="anos" />
                  </div>
                  <div style={{ flex: 2, minWidth: 160 }}>
                    <label className="rp-label">Características de comportamento</label>
                    <input className="rp-input" value={formPet.obs} onChange={(e) => setNovoPet({ ...novoPet, [c.id]: { ...formPet, obs: e.target.value } })} placeholder="Ex: dócil, medo de barulho" />
                  </div>
                  <div>
                    <label className="rp-label">Pet móvel</label>
                    <label style={{ fontSize: 13, display: "flex", alignItems: "center", gap: 6, height: 36 }}>
                      <input type="checkbox" checked={formPet.usaPetMovel} onChange={(e) => setNovoPet({ ...novoPet, [c.id]: { ...formPet, usaPetMovel: e.target.checked } })} /> Usa
                    </label>
                  </div>
                  <div>
                    <label className="rp-label">Foto</label>
                    <label className="rp-btn-ghost" style={{ display: "inline-flex", alignItems: "center", gap: 6, cursor: "pointer" }}>
                      <Camera size={14} /> {formPet.foto ? "Trocada" : "Subir"}
                      <input type="file" accept="image/*" style={{ display: "none" }} onChange={(e) => onFoto(c.id, e.target.files[0], null)} />
                    </label>
                  </div>
                  <button className="rp-btn" onClick={() => addPet(c.id)}>Adicionar pet</button>
                </div>
              </div>
            )}

            {(() => {
              const petSel = petsDoCliente.find((p) => p.id === pacoteAberto);
              if (!petSel) return null;
              const pacotesDoPetSel = db.pacotes.filter((pac) => pac.petId === petSel.id);
              const np = novoPacotePet[petSel.id] || { nome: "", creditosTotal: "", valorPago: "", planoBase: "" };
              return (
                <div style={{ marginTop: 14, paddingTop: 14, borderTop: "1px solid #F8F1E0" }}>
                  <div style={{ fontSize: 13, fontWeight: 600, marginBottom: 8 }}>
                    <PackageOpen size={14} style={{ verticalAlign: -2 }} /> Pacotes de {petSel.nome}
                  </div>
                  {pacotesDoPetSel.length === 0 && <div style={{ fontSize: 12, color: "#96876F", marginBottom: 10 }}>Nenhum pacote registrado ainda.</div>}
                  {pacotesDoPetSel.map((pac) => (
                    <div key={pac.id} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", fontSize: 13, padding: "8px 0", borderBottom: "1px solid #F8F1E0" }}>
                      <span>
                        {pac.nome} · comprado em {pac.dataCompra.split("-").reverse().join("/")} · {brl(pac.valorPago)}
                        {pac.descricao && <div style={{ fontSize: 11, color: "#96876F", marginTop: 2 }}>{pac.descricao}</div>}
                      </span>
                      <span style={{ display: "flex", alignItems: "center", gap: 10 }}>
                        <span style={{ color: "#96876F" }}>{pac.creditosTotal - pac.creditosUsados} de {pac.creditosTotal} restantes</span>
                        <Trash2 size={13} style={{ cursor: "pointer", color: "#A5493A" }} onClick={() => removerPacote(pac.id)} />
                      </span>
                    </div>
                  ))}
                  <div style={{ marginTop: 12 }}>
                    <label className="rp-label">Plano</label>
                    <select
                      className="rp-select"
                      style={{ maxWidth: 320 }}
                      value={np.planoBase || ""}
                      onChange={(e) => {
                        const escolhido = PLANOS_PADRAO.find((pl) => pl.nome === e.target.value);
                        if (escolhido) {
                          setNovoPacotePet({ ...novoPacotePet, [petSel.id]: { nome: escolhido.nome, creditosTotal: escolhido.creditosTotal, valorPago: escolhido.valorPago, planoBase: escolhido.nome } });
                        } else {
                          setNovoPacotePet({ ...novoPacotePet, [petSel.id]: { ...np, planoBase: "" } });
                        }
                      }}
                    >
                      <option value="">Personalizado</option>
                      {PLANOS_PADRAO.map((pl) => (
                        <option key={pl.nome} value={pl.nome}>{pl.nome} — {pl.creditosTotal} banhos — {brl(pl.valorPago)}</option>
                      ))}
                    </select>
                    {np.planoBase && (
                      <div style={{ fontSize: 11, color: "#96876F", marginTop: 4, maxWidth: 400 }}>
                        {PLANOS_PADRAO.find((pl) => pl.nome === np.planoBase)?.descricao}
                      </div>
                    )}
                  </div>
                  <div style={{ display: "flex", gap: 10, flexWrap: "wrap", alignItems: "flex-end", marginTop: 12 }}>
                    <div style={{ minWidth: 160 }}>
                      <label className="rp-label">Nome do pacote</label>
                      <input className="rp-input" value={np.nome} onChange={(e) => setNovoPacotePet({ ...novoPacotePet, [petSel.id]: { ...np, nome: e.target.value } })} />
                    </div>
                    <div style={{ minWidth: 90 }}>
                      <label className="rp-label">Créditos</label>
                      <input type="number" className="rp-input" value={np.creditosTotal} onChange={(e) => setNovoPacotePet({ ...novoPacotePet, [petSel.id]: { ...np, creditosTotal: e.target.value } })} />
                    </div>
                    <div style={{ minWidth: 110 }}>
                      <label className="rp-label">Valor pago</label>
                      <input type="number" className="rp-input" value={np.valorPago} onChange={(e) => setNovoPacotePet({ ...novoPacotePet, [petSel.id]: { ...np, valorPago: e.target.value } })} />
                    </div>
                    <button className="rp-btn" onClick={() => criarPacote(petSel.id)}><Plus size={14} style={{ verticalAlign: -2 }} /> Registrar venda</button>
                  </div>
                </div>
              );
            })()}
          </div>
        );
      })}
    </div>
  );
}

function Agenda({ db, persist }) {
  const [form, setForm] = useState({ clienteId: "", petId: "", servicoIds: [], pacoteId: "", data: todayISO(), hora: "09:00" });

  const petsDoCliente = db.pets.filter((p) => p.clienteId === form.clienteId);
  const pacotesDoPet = db.pacotes.filter((p) => p.petId === form.petId && p.creditosUsados < p.creditosTotal);
  const precoServicos = form.servicoIds.reduce((s, id) => s + (db.servicos.find((sv) => sv.id === id)?.preco || 0), 0);

  const toggleServico = (id) => {
    const jaTem = form.servicoIds.includes(id);
    setForm({
      ...form,
      servicoIds: jaTem ? form.servicoIds.filter((x) => x !== id) : [...form.servicoIds, id],
      pacoteId: "",
    });
  };

  const criarAgendamento = () => {
    if (!form.petId || !form.data || !form.hora) return;
    if (!form.pacoteId && form.servicoIds.length === 0) return;
    const ag = {
      id: uid(),
      clienteId: form.clienteId,
      petId: form.petId,
      servicoIds: form.pacoteId ? [] : form.servicoIds,
      pacoteId: form.pacoteId || null,
      data: form.data,
      hora: form.hora,
      preco: form.pacoteId ? 0 : precoServicos,
      status: "agendado",
    };
    persist({ ...db, agendamentos: [...db.agendamentos, ag] });
    setForm({ ...form, servicoIds: [], pacoteId: "" });
  };

  const concluir = (ag) => {
    let next = { ...db };
    next.agendamentos = db.agendamentos.map((a) => (a.id === ag.id ? { ...a, status: "concluido" } : a));
    if (ag.pacoteId) {
      next.pacotes = db.pacotes.map((p) => (p.id === ag.pacoteId ? { ...p, creditosUsados: p.creditosUsados + 1 } : p));
    } else if (ag.preco > 0) {
      const nomesServicos = (ag.servicoIds || []).map((id) => db.servicos.find((s) => s.id === id)?.nome).filter(Boolean).join(" + ");
      const pet = db.pets.find((p) => p.id === ag.petId);
      next.financeiro = [...db.financeiro, { id: uid(), tipo: "entrada", categoria: "Serviço", valor: ag.preco, data: todayISO(), descricao: `${nomesServicos || "Serviço"} — ${pet?.nome || ""}` }];
    }
    persist(next);
  };

  const cancelar = (id) => persist({ ...db, agendamentos: db.agendamentos.map((a) => (a.id === id ? { ...a, status: "cancelado" } : a)) });
  const remover = (id) => persist({ ...db, agendamentos: db.agendamentos.filter((a) => a.id !== id) });

  const nome = (id, arr) => arr.find((x) => x.id === id)?.nome || "—";
  const lista = [...db.agendamentos].sort((a, b) => (a.data + a.hora).localeCompare(b.data + b.hora));

  return (
    <div>
      <h2 className="rp-title" style={{ fontSize: 21, margin: "0 0 4px" }}>Agenda</h2>
      <p style={{ color: "#96876F", fontSize: 13, margin: "0 0 20px" }}>
        A agenda vive aqui dentro; use "Adicionar à Google Agenda" em cada horário para também colocá-lo na sua Google Agenda do negócio. Pacotes são vendidos na tela de Clientes e pets.
      </p>

      <div className="rp-card" style={{ marginBottom: 20 }}>
        <div style={{ fontWeight: 600, fontSize: 14, marginBottom: 10 }}>Novo agendamento</div>
        <div style={{ display: "flex", gap: 10, flexWrap: "wrap", alignItems: "flex-end" }}>
          <div style={{ minWidth: 160 }}>
            <label className="rp-label">Cliente</label>
            <select className="rp-select" value={form.clienteId} onChange={(e) => setForm({ ...form, clienteId: e.target.value, petId: "" })}>
              <option value="">Selecione</option>
              {db.clientes.map((c) => <option key={c.id} value={c.id}>{c.nome}</option>)}
            </select>
          </div>
          <div style={{ minWidth: 140 }}>
            <label className="rp-label">Pet</label>
            <select className="rp-select" value={form.petId} onChange={(e) => setForm({ ...form, petId: e.target.value })}>
              <option value="">Selecione</option>
              {petsDoCliente.map((p) => <option key={p.id} value={p.id}>{p.nome}</option>)}
            </select>
          </div>
          <div style={{ minWidth: 130 }}>
            <label className="rp-label">Data</label>
            <input type="date" className="rp-input" value={form.data} onChange={(e) => setForm({ ...form, data: e.target.value })} />
          </div>
          <div style={{ minWidth: 100 }}>
            <label className="rp-label">Hora</label>
            <input type="time" className="rp-input" value={form.hora} onChange={(e) => setForm({ ...form, hora: e.target.value })} />
          </div>
        </div>

        <div style={{ marginTop: 14, paddingTop: 14, borderTop: "1px solid #F8F1E0", display: "flex", gap: 20, flexWrap: "wrap" }}>
          <div style={{ minWidth: 220 }}>
            <label className="rp-label">Serviços (pode marcar mais de um)</label>
            <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
              {db.servicos.map((s) => (
                <label key={s.id} style={{ fontSize: 13, display: "flex", alignItems: "center", gap: 6, opacity: form.pacoteId ? 0.4 : 1 }}>
                  <input
                    type="checkbox"
                    disabled={!!form.pacoteId}
                    checked={form.servicoIds.includes(s.id)}
                    onChange={() => toggleServico(s.id)}
                  />
                  {s.nome} — {brl(s.preco)}
                </label>
              ))}
            </div>
            {form.servicoIds.length > 0 && (
              <div style={{ fontSize: 13, fontWeight: 600, marginTop: 8 }}>Total: {brl(precoServicos)}</div>
            )}
          </div>

          <div style={{ minWidth: 220 }}>
            <label className="rp-label">Ou usar crédito de pacote</label>
            <select
              className="rp-select"
              value={form.pacoteId}
              onChange={(e) => setForm({ ...form, pacoteId: e.target.value, servicoIds: [] })}
            >
              <option value="">Nenhum</option>
              {pacotesDoPet.map((p) => (
                <option key={p.id} value={p.id}>{p.nome} ({p.creditosTotal - p.creditosUsados} restantes)</option>
              ))}
            </select>
            {pacotesDoPet.length === 0 && (
              <div style={{ fontSize: 11, color: "#96876F", marginTop: 4 }}>Este pet não tem créditos ativos.</div>
            )}
          </div>
        </div>

        <button className="rp-btn" style={{ marginTop: 14 }} onClick={criarAgendamento}><Plus size={14} style={{ verticalAlign: -2 }} /> Agendar</button>
      </div>

      {lista.length === 0 && <div style={{ color: "#96876F", fontSize: 13 }}>Nenhum agendamento ainda.</div>}
      {lista.map((a) => {
        const pet = db.pets.find((p) => p.id === a.petId);
        const nomesServicos = (a.servicoIds || []).map((id) => nome(id, db.servicos)).join(" + ");
        const pacote = a.pacoteId ? db.pacotes.find((p) => p.id === a.pacoteId) : null;
        const link = gcalLink({ titulo: `${pet?.nome || "Pet"} — ${nomesServicos || pacote?.nome || "Serviço"} · Refúgio do Pet`, dataISO: a.data, hora: a.hora, detalhes: `Agendamento do Refúgio do Pet` });
        return (
          <div key={a.id} className="rp-card" style={{ marginBottom: 10, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <div>
              <div style={{ fontWeight: 500, fontSize: 14 }}>{pet?.nome || "—"} · {nomesServicos || (pacote ? `Crédito: ${pacote.nome}` : "—")}</div>
              <div style={{ fontSize: 12, color: "#96876F" }}>{a.data.split("-").reverse().join("/")} às {a.hora} · {a.preco > 0 ? brl(a.preco) : "sem cobrança (crédito)"}</div>
            </div>
            <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
              <span className="rp-tag" style={{
                background: a.status === "concluido" ? "#E1EBE0" : a.status === "cancelado" ? "#F5E4DF" : "#F8F1E0",
                color: a.status === "concluido" ? "#065748" : a.status === "cancelado" ? "#A5493A" : "#8C7A67",
              }}>{a.status}</span>
              <a href={link} target="_blank" rel="noopener noreferrer" className="rp-btn-ghost" style={{ textDecoration: "none", display: "inline-flex", alignItems: "center", gap: 4 }}>
                <ExternalLink size={12} /> Google Agenda
              </a>
              {a.status === "agendado" && (
                <button className="rp-btn-ghost" onClick={() => concluir(a)}><CheckCircle2 size={13} style={{ verticalAlign: -2 }} /> Concluir</button>
              )}
              {a.status === "agendado" && (
                <button className="rp-btn-ghost" onClick={() => cancelar(a.id)}>Cancelar</button>
              )}
              <button className="rp-btn-danger" onClick={() => remover(a.id)}><Trash2 size={13} /></button>
            </div>
          </div>
        );
      })}
    </div>
  );
}

function Financeiro({ db, persist }) {
  const [form, setForm] = useState({ tipo: "entrada", categoria: "", valor: "", data: todayISO(), descricao: "" });
  const [filtroMes, setFiltroMes] = useState(todayISO().slice(0, 7));

  const add = () => {
    if (!form.valor || !form.categoria) return;
    persist({ ...db, financeiro: [...db.financeiro, { id: uid(), ...form, valor: Number(form.valor) }] });
    setForm({ tipo: "entrada", categoria: "", valor: "", data: todayISO(), descricao: "" });
  };

  const remover = (id) => persist({ ...db, financeiro: db.financeiro.filter((f) => f.id !== id) });

  const doMes = db.financeiro.filter((f) => f.data.startsWith(filtroMes)).sort((a, b) => b.data.localeCompare(a.data));
  const entradas = doMes.filter((f) => f.tipo === "entrada").reduce((s, f) => s + f.valor, 0);
  const saidas = doMes.filter((f) => f.tipo === "saida").reduce((s, f) => s + f.valor, 0);

  return (
    <div>
      <h2 className="rp-title" style={{ fontSize: 21, margin: "0 0 4px" }}>Financeiro</h2>
      <p style={{ color: "#96876F", fontSize: 13, margin: "0 0 20px" }}>Entradas de serviço concluído entram sozinhas; o resto você lança aqui.</p>

      <div className="rp-card" style={{ marginBottom: 16 }}>
        <div style={{ fontWeight: 600, fontSize: 14, marginBottom: 10 }}>Novo lançamento</div>
        <div style={{ display: "flex", gap: 10, flexWrap: "wrap", alignItems: "flex-end" }}>
          <div style={{ minWidth: 110 }}>
            <label className="rp-label">Tipo</label>
            <select className="rp-select" value={form.tipo} onChange={(e) => setForm({ ...form, tipo: e.target.value })}>
              <option value="entrada">Entrada</option>
              <option value="saida">Saída</option>
            </select>
          </div>
          <div style={{ minWidth: 140 }}>
            <label className="rp-label">Categoria</label>
            <input className="rp-input" value={form.categoria} onChange={(e) => setForm({ ...form, categoria: e.target.value })} placeholder="Ex: aluguel, produtos" />
          </div>
          <div style={{ minWidth: 110 }}>
            <label className="rp-label">Valor</label>
            <input type="number" className="rp-input" value={form.valor} onChange={(e) => setForm({ ...form, valor: e.target.value })} />
          </div>
          <div style={{ minWidth: 130 }}>
            <label className="rp-label">Data</label>
            <input type="date" className="rp-input" value={form.data} onChange={(e) => setForm({ ...form, data: e.target.value })} />
          </div>
          <div style={{ flex: 1, minWidth: 160 }}>
            <label className="rp-label">Descrição</label>
            <input className="rp-input" value={form.descricao} onChange={(e) => setForm({ ...form, descricao: e.target.value })} />
          </div>
          <button className="rp-btn" onClick={add}><Plus size={14} style={{ verticalAlign: -2 }} /> Lançar</button>
        </div>
      </div>

      <div style={{ display: "flex", gap: 12, marginBottom: 14, alignItems: "center" }}>
        <label className="rp-label" style={{ marginBottom: 0 }}>Mês</label>
        <input type="month" className="rp-input" style={{ width: 160 }} value={filtroMes} onChange={(e) => setFiltroMes(e.target.value)} />
        <div style={{ fontSize: 13, color: "#96876F" }}>Entradas: <b style={{ color: "#3A2E24" }}>{brl(entradas)}</b> · Saídas: <b style={{ color: "#3A2E24" }}>{brl(saidas)}</b> · Saldo: <b style={{ color: entradas - saidas < 0 ? "#A5493A" : "#3A2E24" }}>{brl(entradas - saidas)}</b></div>
      </div>

      {doMes.length === 0 && <div style={{ color: "#96876F", fontSize: 13 }}>Nenhum lançamento neste mês.</div>}
      {doMes.map((f) => (
        <div key={f.id} className="rp-card" style={{ marginBottom: 8, display: "flex", justifyContent: "space-between", alignItems: "center", padding: "12px 16px" }}>
          <div>
            <span className="rp-tag" style={{ background: f.tipo === "entrada" ? "#E1EBE0" : "#F5E4DF", color: f.tipo === "entrada" ? "#065748" : "#A5493A", marginRight: 8 }}>
              {f.tipo === "entrada" ? "entrada" : "saída"}
            </span>
            <span style={{ fontSize: 14 }}>{f.categoria}{f.descricao ? ` — ${f.descricao}` : ""}</span>
          </div>
          <div style={{ display: "flex", gap: 12, alignItems: "center" }}>
            <span style={{ fontSize: 13, color: "#96876F" }}>{f.data.split("-").reverse().join("/")}</span>
            <span style={{ fontWeight: 600, fontSize: 14 }}>{brl(f.valor)}</span>
            <button className="rp-btn-danger" onClick={() => remover(f.id)}><Trash2 size={13} /></button>
          </div>
        </div>
      ))}
    </div>
  );
}

function Servicos({ db, persist }) {
  const [novo, setNovo] = useState({ nome: "", preco: "" });
  const add = () => {
    if (!novo.nome || !novo.preco) return;
    persist({ ...db, servicos: [...db.servicos, { id: uid(), nome: novo.nome, preco: Number(novo.preco) }] });
    setNovo({ nome: "", preco: "" });
  };
  const remover = (id) => persist({ ...db, servicos: db.servicos.filter((s) => s.id !== id) });

  return (
    <div>
      <h2 className="rp-title" style={{ fontSize: 21, margin: "0 0 4px" }}>Serviços e preços</h2>
      <p style={{ color: "#96876F", fontSize: 13, margin: "0 0 20px" }}>O catálogo usado na Agenda.</p>

      <div className="rp-card" style={{ marginBottom: 16, display: "flex", gap: 10, alignItems: "flex-end" }}>
        <div style={{ flex: 1 }}>
          <label className="rp-label">Serviço</label>
          <input className="rp-input" value={novo.nome} onChange={(e) => setNovo({ ...novo, nome: e.target.value })} />
        </div>
        <div style={{ width: 140 }}>
          <label className="rp-label">Preço</label>
          <input type="number" className="rp-input" value={novo.preco} onChange={(e) => setNovo({ ...novo, preco: e.target.value })} />
        </div>
        <button className="rp-btn" onClick={add}><Plus size={14} style={{ verticalAlign: -2 }} /> Adicionar</button>
      </div>

      {db.servicos.map((s) => (
        <div key={s.id} className="rp-card" style={{ marginBottom: 8, display: "flex", justifyContent: "space-between", alignItems: "center", padding: "12px 16px" }}>
          <span style={{ fontSize: 14 }}>{s.nome}</span>
          <div style={{ display: "flex", gap: 12, alignItems: "center" }}>
            <span style={{ fontWeight: 600 }}>{brl(s.preco)}</span>
            <button className="rp-btn-danger" onClick={() => remover(s.id)}><Trash2 size={13} /></button>
          </div>
        </div>
      ))}
    </div>
  );
}
